238	    proxy: CGEventTapProxy,
239	    type event_type: CGEventType,
240	    event: CGEvent,
241	    userInfo: UnsafeMutableRawPointer?
242	) -> Unmanaged<CGEvent>? {
243	    guard let userInfo else {
244	        return Unmanaged.passUnretained(event)
245	    }
246	    let app_delegate = Unmanaged<AppDelegate>
247	            .fromOpaque(userInfo)
248	            .takeUnretainedValue()
249	    if event_type == .tapDisabledByTimeout || event_type == .tapDisabledByUserInput {
250	        app_delegate.enable_event_tap()
251	        return Unmanaged.passUnretained(event)
252	    }
253	    guard event_type == .keyDown else {
254	        return Unmanaged.passUnretained(event)
255	    }
256	    if event.getIntegerValueField(.eventSourceUserData) == synthetic_event_source_user_data {
257	        return Unmanaged.passUnretained(event)
258	    }
259	    var character_count = 0
260	    event.keyboardGetUnicodeString(
261	        maxStringLength: 0,
262	        actualStringLength: &character_count,
263	        unicodeString: nil
264	    )
265	    if character_count > 0 {
266	        var characters = [UniChar](repeating: 0, count: character_count)
267	        event.keyboardGetUnicodeString(
268	            maxStringLength: character_count,
269	            actualStringLength: &character_count,
270	            unicodeString: &characters
271	        )
272	        let s = String(
273	            utf16CodeUnits: characters,
274	            count: character_count
275	        )
276	        print("Input character: \(s)")
277	    } else {
278	        let key_code = event.getIntegerValueField(.keyboardEventKeycode)
279	        print("Input key code: \(key_code)")
280	    }
281	    NSSound(named: "Tink")?.play()
282	    return Unmanaged.passUnretained(event)
283	}
