2062: test "expect State.add auto-fill missing horn in valid cases" {
2063:     // Arrange: starting pair shapes covering both auto-fill targets and all
2064:     // case combinations. `receiving_offset` marks which vowel in the pair
2065:     // gains horn (0 = first, 1 = second).
2066:     const PairCase = struct {
2067:         first_base: u8,
2068:         first_diacritic: Diacritic,
2069:         second_base: u8,
2070:         second_diacritic: Diacritic,
2071:         receiving_offset: u8,
2072:     };
2073:     const pair_cases = [_]PairCase{
2074:         // uơ pattern: first vowel is missing horn.
2075:         .{ .first_base = 'u', .first_diacritic = .empty, .second_base = 'o', .second_diacritic = .horn, .receiving_offset = 0 },
2076:         .{ .first_base = 'u', .first_diacritic = .empty, .second_base = 'O', .second_diacritic = .horn, .receiving_offset = 0 },
2077:         .{ .first_base = 'U', .first_diacritic = .empty, .second_base = 'o', .second_diacritic = .horn, .receiving_offset = 0 },
2078:         .{ .first_base = 'U', .first_diacritic = .empty, .second_base = 'O', .second_diacritic = .horn, .receiving_offset = 0 },
2079:         // ưo pattern: second vowel is missing horn.
2080:         .{ .first_base = 'u', .first_diacritic = .horn, .second_base = 'o', .second_diacritic = .empty, .receiving_offset = 1 },
2081:         .{ .first_base = 'u', .first_diacritic = .horn, .second_base = 'O', .second_diacritic = .empty, .receiving_offset = 1 },
2082:         .{ .first_base = 'U', .first_diacritic = .horn, .second_base = 'o', .second_diacritic = .empty, .receiving_offset = 1 },
2083:         .{ .first_base = 'U', .first_diacritic = .horn, .second_base = 'O', .second_diacritic = .empty, .receiving_offset = 1 },
2084:     };
2085: 
2086:     const triggers = [_]u8{ 'C', 'c', 'I', 'i', 'M', 'm', 'N', 'n', 'P', 'p', 'T', 't', 'U', 'u' };
2087: 
2088:     const tones = [_]Tone{ .level, .rising, .falling, .dipping_rising, .rising_glottalized, .falling_glottalized };
2089: 
2090:     // Linguistically valid one-tone syllables: a tone may sit on either vowel.
2091:     // Sweep both positions while the other vowel stays at .level. We do not
2092:     // fabricate double-toned syllables that the spec would not consider valid.
2093:     const tone_positions = [_]u8{ 0, 1 };
2094: 
2095:     // Cover both pair-at-start (no prefix) and pair-after-consonant variants
2096:     // to prove the rule looks at the last two spans regardless of buffer_length.
2097:     const prefix_lengths = [_]u8{ 0, 1 };
2098: 
2099:     for (pair_cases) |pc| {
2100:         for (triggers) |trig| {
2101:             for (tones) |tn| {
2102:                 for (tone_positions) |tpos| {
2103:                     for (prefix_lengths) |plen| {
2104:                         var state: State = undefined;
2105:                         state.init();
2106: 
2107:                         // Optional 'b' prefix to place the pair at index 1..2.
2108:                         if (plen == 1) {
2109:                             state.buffer_effective[0] = Span.init('b');
2110:                         }
2111: 
2112:                         const first_tone: Tone = if (tpos == 0) tn else .level;
2113:                         const second_tone: Tone = if (tpos == 1) tn else .level;
2114: 
2115:                         state.buffer_effective[plen] = Span.init_diacritic_tone(pc.first_base, pc.first_diacritic, first_tone);
2116:                         state.buffer_effective[plen + 1] = Span.init_diacritic_tone(pc.second_base, pc.second_diacritic, second_tone);
2117:                         state.buffer_length = plen + 2;
2118: 
2119:                         // Act
2120:                         state.add(trig);
2121: 
2122:                         // Assert
2123:                         const receiving_index = plen + pc.receiving_offset;
2124:                         try expectEqual(plen + 3, state.buffer_length);
2125:                         try expectEqual(receiving_index, state.buffer_modification_index);
2126:                         try expectEqual(null, state.literal_index);
2127: 
2128:                         // Prefix, when present, must be unchanged.
2129:                         if (plen == 1) {
2130:                             const sp_prefix = state.buffer_effective[0];
2131:                             try expectEqual(@as(u8, 'b'), sp_prefix.base);
2132:                             try expectEqual(.empty, sp_prefix.diacritic);
2133:                             try expectEqual(.level, sp_prefix.tone);
2134:                         }
2135: 
2136:                         // Both vowel spans must end with horn; case and tone preserved.
2137:                         const sp_first = state.buffer_effective[plen];
2138:                         try expectEqual(pc.first_base, sp_first.base);
2139:                         try expectEqual(.horn, sp_first.diacritic);
2140:                         try expectEqual(first_tone, sp_first.tone);
2141: 
2142:                         const sp_second = state.buffer_effective[plen + 1];
2143:                         try expectEqual(pc.second_base, sp_second.base);
2144:                         try expectEqual(.horn, sp_second.diacritic);
2145:                         try expectEqual(second_tone, sp_second.tone);
2146: 
2147:                         // The trigger character is appended literally.
2148:                         const sp_new = state.buffer_effective[plen + 2];
2149:                         try expectEqual(trig, sp_new.base);
2150:                         try expectEqual(.empty, sp_new.diacritic);
2151:                         try expectEqual(.level, sp_new.tone);
2152:                     }
2153:                 }
2154:             }
2155:         }
