2792: test "expect State.add cancels an existing matching non-level tone for representative cases and switches to literal input" {
2793:     // Arrange. This test proves State.add takes the cancellation arm for each non-level tone:
2794:     // reset the existing matching tone to level (preserving base case + diacritic), append the
2795:     // trigger literally, and set literal_index to the pre-append buffer_length.
2796:     // Tone-position rules are NOT re-evaluated here; they are covered by State.apply_tone tests.
2797:     const TriggerCase = enum { lower, upper };
2798:     const ToneCase = struct {
2799:         tone: Tone,
2800:         lower_trigger: u8,
2801:         upper_trigger: u8,
2802:     };
2803:     const SeedSpan = struct { base: u8, diacritic: Diacritic = .empty };
2804:     const Case = struct {
2805:         seeds: []const SeedSpan,
2806:         trigger_case: TriggerCase,
2807:         // Absolute buffer index of the seeded vowel that carries the existing matching tone, which
2808:         // is also the expected buffer_modification_index after cancellation.
2809:         expected_modification_index: u8,
2810:     };
2811:     const tone_cases = [_]ToneCase{
2812:         .{ .tone = .rising, .lower_trigger = 's', .upper_trigger = 'S' },
2813:         .{ .tone = .falling, .lower_trigger = 'f', .upper_trigger = 'F' },
2814:         .{ .tone = .dipping_rising, .lower_trigger = 'r', .upper_trigger = 'R' },
2815:         .{ .tone = .rising_glottalized, .lower_trigger = 'x', .upper_trigger = 'X' },
2816:         .{ .tone = .falling_glottalized, .lower_trigger = 'j', .upper_trigger = 'J' },
2817:     };
2818:     const cases = [_]Case{
2819:         // Lowercase trigger, single plain vowel.
2820:         .{
2821:             .seeds = &.{.{ .base = 'a' }},
2822:             .trigger_case = .lower,
2823:             .expected_modification_index = 0,
2824:         },
2825:         // Uppercase trigger, single plain vowel.
2826:         .{
2827:             .seeds = &.{.{ .base = 'A' }},
2828:             .trigger_case = .upper,
2829:             .expected_modification_index = 0,
2830:         },
2831:         // Consonant + plain vowel (open syllable).
2832:         .{
2833:             .seeds = &.{ .{ .base = 'b' }, .{ .base = 'a' } },
2834:             .trigger_case = .lower,
2835:             .expected_modification_index = 1,
2836:         },
2837:         // Trailing consonant (closed syllable). The trailing 'n' must remain untouched.
2838:         .{
2839:             .seeds = &.{ .{ .base = 'b' }, .{ .base = 'a' }, .{ .base = 'n' } },
2840:             .trigger_case = .lower,
2841:             .expected_modification_index = 1,
2842:         },
2843:         // Trailing consonant cluster. The trailing 'nh' cluster must remain untouched.
2844:         .{
2845:             .seeds = &.{ .{ .base = 'b' }, .{ .base = 'a' }, .{ .base = 'n' }, .{ .base = 'h' } },
2846:             .trigger_case = .lower,
2847:             .expected_modification_index = 1,
2848:         },
2849:         // Diacritic-bearing vowel with trailing consonant. Cancellation must keep the circumflex.
2850:         .{
2851:             .seeds = &.{ .{ .base = 't' }, .{ .base = 'i' }, .{ .base = 'e', .diacritic = .circumflex }, .{ .base = 'n' } },
2852:             .trigger_case = .lower,
2853:             .expected_modification_index = 2,
2854:         },
2855:         // Multi-vowel representative shape. This does not assert OA tone-placement rules.
2856:         .{
2857:             .seeds = &.{ .{ .base = 'h' }, .{ .base = 'o' }, .{ .base = 'a' } },
2858:             .trigger_case = .lower,
2859:             .expected_modification_index = 1,
2860:         },
2861:         // Longer buffer trailing-suffix. Only the last syllable's vowel carries the matching tone,
2862:         // so cancellation lands at index 4 and earlier spans remain exactly as seeded.
2863:         .{
2864:             .seeds = &.{ .{ .base = 'v' }, .{ .base = 'a' }, .{ .base = 'n' }, .{ .base = 'h' }, .{ .base = 'o' }, .{ .base = 'a' } },
2865:             .trigger_case = .lower,
2866:             .expected_modification_index = 4,
2867:         },
2868:     };
2869: 
2870:     for (tone_cases) |tone_case| {
2871:         for (cases) |c| {
2872:             var state: State = undefined;
2873:             state.init();
2874:             for (c.seeds, 0..) |s, i| {
2875:                 const tone: Tone = if (i == @as(usize, c.expected_modification_index))
2876:                     tone_case.tone
2877:                 else
2878:                     .level;
2879:                 state.buffer_effective[i] = Span.init_diacritic_tone(s.base, s.diacritic, tone);
2880:             }
2881:             state.buffer_length = @intCast(c.seeds.len);
2882: 
2883:             const trigger = switch (c.trigger_case) {
2884:                 .lower => tone_case.lower_trigger,
2885:                 .upper => tone_case.upper_trigger,
2886:             };
2887: 
2888:             // Setup guard: prevent expected_modification_index from drifting away from seed data.
2889:             try expectEqual(
2890:                 tone_case.tone,
2891:                 state.buffer_effective[c.expected_modification_index].tone,
2892:             );
2893: 
2894:             // Act
2895:             state.add(trigger);
2896: 
2897:             // Assert: the trigger character is appended literally, the matching tone on the seeded
2898:             // vowel is reset to level, and literal_index marks the new literal span.
2899:             try expectEqual(@as(u8, @intCast(c.seeds.len + 1)), state.buffer_length);
2900:             try expectEqual(@as(?u8, c.expected_modification_index), state.buffer_modification_index);
2901:             try expectEqual(@as(?u8, @intCast(c.seeds.len)), state.literal_index);
2902: 
2903:             // Every preexisting span keeps its base + diacritic; the cancelled vowel drops to level
2904:             // (others were already level and remain so).
2905:             for (c.seeds, 0..) |s, i| {
2906:                 const sp = state.buffer_effective[i];
2907:                 try expectEqual(s.base, sp.base);
2908:                 try expectEqual(s.diacritic, sp.diacritic);
2909:                 try expectEqual(.level, sp.tone);
2910:             }
2911: 
2912:             // The appended trigger span is plain literal: same base char, no diacritic, no tone.
2913:             const appended = state.buffer_effective[c.seeds.len];
2914:             try expectEqual(trigger, appended.base);
2915:             try expectEqual(.empty, appended.diacritic);
2916:             try expectEqual(.level, appended.tone);
2917:         }
2918:     }
2919: }
